using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // In .NET 9, ZipArchiveEntry respects the UTF-8 flag by default.
        // The legacy Java consumer expects Shift-JIS filenames, so specify
        // the encoding explicitly to avoid writing UTF-8 flagged entries.
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, Encoding.GetEncoding("shift_jis"));
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

// In .NET 9, [FromKeyedServices] no longer falls back to non-keyed
// registrations — it throws InvalidOperationException. Register as keyed.
services.AddKeyedSingleton<ICache, RedisCache>("cache");

